func (l *LList) Clear() {
	if l.Size == 0 {
		return
	}
	for n := l.root.next; n != &l.root; {
		next := n.next
		n.prev = nil
		n.next = nil
		n = next
	}
	l.root.next = &l.root
	l.root.prev = &l.root
	l.Size = 0
}

func (l *LList) Search(value int) *Node {
	for n := l.Front(); n != nil; n = n.Next() {
		if n.value == value {
			return n
		}
	}
	return nil
